INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 2, "2023/06/30 12:00:00", 1, "いらっしゃいませっ♪\nキャラバンコインを使って\n買い物ができますよっ！", 2002, "2023/09/22 14:59:59", 10001, 1, 1.47, 126401, "クローチェ", 0.0, -470.0);
