INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 2, "2023/06/30 12:00:00", 1, "ショップへようこそ\nキャラバンコインはこちら\nで買い物に使えますよ", 2002, "2023/09/22 14:59:59", 10003, 1, 0.0, 126501, "ライラエル", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 1, "2023/06/30 12:00:00", 2, "こちらのショップで\n買い物をして、素敵な\n旅を楽しんでくださいね", 2002, "2023/09/22 14:59:59", 10004, 1, 0.0, 126501, "ライラエル", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 2, "2023/09/15 15:00:00", 1, "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ", 2002, "2023/12/22 14:59:59", 10005, 2, 0.0, 127702, "リンド", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 2, "2023/09/15 15:00:00", 2, "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから", 2002, "2023/12/22 14:59:59", 10006, 2, 0.0, 127702, "リンド", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 1, "2023/09/15 15:00:00", 1, "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ", 2002, "2023/12/22 14:59:59", 10007, 2, 0.0, 127802, "ヴルム", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 1, "2023/09/15 15:00:00", 2, "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ", 2002, "2023/12/22 14:59:59", 10008, 2, 6.5, 127802, "ヴルム", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 1, "2023/12/15 15:00:00", 1, "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", 2002, "2024/03/22 14:59:59", 10009, 3, 0.0, 129602, "アネモネ", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 1, "2023/12/15 15:00:00", 2, "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから", 2002, "2024/03/22 14:59:59", 10010, 3, 0.0, 129602, "アネモネ", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 1, "2023/12/15 15:00:00", 1, "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", 2002, "2024/03/22 14:59:59", 10011, 3, 0.0, 129701, "ネフィ=ネラ", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 1, "2023/12/15 15:00:00", 2, "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", 2002, "2024/03/22 14:59:59", 10012, 3, 6.2, 129701, "ネフィ=ネラ", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (3, 5, "2024/03/15 15:00:00", 1, "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", 2002, "2024/06/22 14:59:59", 10013, 4, 3.1, 130301, "カノン", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (3, 2, "2024/03/15 15:00:00", 2, "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", 2002, "2024/06/22 14:59:59", 10014, 4, 6.15, 130301, "カノン", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 2, "2024/03/15 15:00:00", 1, "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", 2002, "2024/06/22 14:59:59", 10015, 4, 0.0, 130401, "ナーナ", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 1, "2024/03/15 15:00:00", 2, "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！", 2002, "2024/06/22 14:59:59", 10016, 4, 3.35, 130401, "ナーナ", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 1, "2024/06/15 15:00:00", 1, "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", 2002, "2024/09/22 14:59:59", 10017, 5, 0.0, 130502, "ホウオウ", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 1, "2024/06/15 15:00:00", 2, "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！", 2002, "2024/09/22 14:59:59", 10018, 5, 3.18, 130502, "ホウオウ", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (4, 4, "2024/06/15 15:00:00", 3, "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", 2002, "2024/09/22 14:59:59", 10019, 5, 0.0, 130503, "ホウオウ", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 2, "2024/06/15 15:00:00", 1, "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", 2002, "2024/09/22 14:59:59", 10020, 5, 4.9, 123301, "ネア", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 2, "2024/06/15 15:00:00", 2, "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", 2002, "2024/09/22 14:59:59", 10021, 5, 4.8, 123301, "ネア", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (3, 1, "2024/09/15 15:00:00", 1, "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", 2002, "2024/12/22 14:59:59", 10022, 6, 4.922, 133301, "カリザ", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (3, 5, "2024/09/15 15:00:00", 2, "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", 2002, "2024/12/22 14:59:59", 10023, 6, 9.638, 133301, "カリザ", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 2, "2024/09/15 15:00:00", 1, "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", 2002, "2024/12/22 14:59:59", 10024, 6, 2.88, 133401, "ミーア", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (5, 1, "2024/09/15 15:00:00", 2, "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！", 2002, "2024/12/22 14:59:59", 10025, 6, 4.818, 133401, "ミーア", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 1, "2024/12/15 15:00:00", 1, "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", 2002, "2025/03/22 14:59:59", 10026, 7, 1.78, 133002, "グレイス", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 7, "2024/12/15 15:00:00", 2, "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが", 2002, "2025/03/22 14:59:59", 10027, 7, 6.15, 133002, "グレイス", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (6, 2, "2024/12/15 15:00:00", 1, "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", 2002, "2025/03/22 14:59:59", 10028, 7, 4.28, 133102, "ヴァイオレット", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 1, "2024/12/15 15:00:00", 2, "じめじめした商品は\nございませんので\n安心してお買い求め下さい", 2002, "2025/03/22 14:59:59", 10029, 7, 0.0, 133102, "ヴァイオレット", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 1, "2025/03/15 15:00:00", 1, "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", 2002, "2025/06/23 14:59:59", 10030, 8, 5.53, 136902, "ルルィ", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (9, 7, "2025/03/15 15:00:00", 2, "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", 2002, "2025/06/23 14:59:59", 10031, 8, 6.05, 136902, "ルルィ", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 1, "2025/03/15 15:00:00", 1, "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", 2002, "2025/06/23 14:59:59", 10032, 8, 0.0, 137001, "デュラン", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 1, "2025/03/15 15:00:00", 2, "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", 2002, "2025/06/23 14:59:59", 10033, 8, 0.0, 137001, "デュラン", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 2, "2025/06/16 15:00:00", 1, "おう\n好きなもん持ってきな", 2002, "2025/09/23 14:59:59", 10034, 9, 0.0, 135902, "サツキ", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 6, "2025/06/16 15:00:00", 2, "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", 2002, "2025/09/23 14:59:59", 10035, 9, 4.935, 135902, "サツキ", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 5, "2025/06/16 15:00:00", 1, "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", 2002, "2025/09/23 14:59:59", 10036, 9, 7.441, 135802, "ユキノ", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (7, 7, "2025/06/16 15:00:00", 2, "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", 2002, "2025/09/23 14:59:59", 10037, 9, 0.0, 135802, "ユキノ", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 2, "2025/09/16 15:00:00", 1, "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", 2002, "2025/12/22 14:59:59", 10038, 10, 2.295, 130901, "クルル", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 6, "2025/09/16 15:00:00", 2, "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", 2002, "2025/12/22 14:59:59", 10039, 10, 6.281, 130901, "クルル", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 1, "2025/09/16 15:00:00", 1, "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", 2002, "2025/12/22 14:59:59", 10040, 10, 5.549, 137701, "ヴォルガーノ", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (3, 6, "2025/09/16 15:00:00", 2, "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", 2002, "2025/12/22 14:59:59", 10041, 10, 2.64, 137701, "ヴォルガーノ", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (7, 4, "2025/12/15 15:00:00", 1, "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", 2002, "2026/03/23 11:59:59", 10042, 11, 7.642, 132801, "ライラエル", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 1, "2025/12/15 15:00:00", 2, "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", 2002, "2026/03/23 11:59:59", 10043, 11, 0.0, 132802, "ライラエル", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 1, "2025/12/15 15:00:00", 1, "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", 2002, "2026/03/23 11:59:59", 10044, 11, 0.0, 134502, "クローチェ", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 1, "2025/12/15 15:00:00", 2, "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", 2002, "2026/03/23 11:59:59", 10045, 11, 3.72, 134501, "クローチェ", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 1, "2026/03/16 12:00:00", 1, "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃", 2002, "2026/06/22 11:59:59", 10046, 12, 4.991, 138201, "ネフィ＝ネラ", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 4, "2026/03/16 12:00:00", 2, "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする", 2002, "2026/06/22 11:59:59", 10047, 12, 3.877, 138201, "ネフィ＝ネラ", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (4, 6, "2026/03/16 12:00:00", 1, "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？", 2002, "2026/06/22 11:59:59", 10048, 12, 1.71, 136001, "アラクネ", 0.0, -470.0);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (5, 2, "2026/03/16 12:00:00", 2, "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…", 2002, "2026/06/22 11:59:59", 10049, 12, 5.32, 136001, "アラクネ", 0.0, -470.0);
